# ---------------------------------------------------------
# Bildverarbeitung
# ---------------------------------------------------------
def normalize_to_srgb(image: Image.Image) -> Image.Image:
    icc = image.info.get("icc_profile")
    if not icc:
        return image
    try:
        input_profile = ImageCms.ImageCmsProfile(io.BytesIO(icc))
        srgb_profile = ImageCms.createProfile("sRGB")
        mode = "RGBA" if image.mode == "RGBA" else "RGB"
        return ImageCms.profileToProfile(image, input_profile, srgb_profile, outputMode=mode)
    except Exception:
        return image


def crop_to_content(img: Image.Image, padding: int = 4) -> Image.Image:
    arr = np.array(img)
    alpha = arr[:, :, 3]
    ys, xs = np.where(alpha > 10)
    if len(xs) == 0:
        return img
    x0, x1 = max(xs.min() - padding, 0), min(xs.max() + padding, img.width)
    y0, y1 = max(ys.min() - padding, 0), min(ys.max() + padding, img.height)
    return img.crop((x0, y0, x1, y1))


ALPHA_FLOOR = 1
# Very conservative final cleanup: only pixels that are virtually invisible
# are removed. This keeps soft watercolor edges intact while preventing a
# faint fringe at extreme zoom.
FINAL_ALPHA_THRESHOLD = 3


def bleed_rgb_into_transparency(img: Image.Image) -> Image.Image:
    """Fill hidden RGB in transparent pixels from the nearest visible pixel.

    PNGs often contain white, grey, or black RGB values under fully transparent
    pixels. Resizing and rotation sample those hidden values and create a halo.
    Filling them with the nearest motif colour prevents that contamination while
    leaving the alpha channel completely unchanged.
    """
    arr = np.asarray(img.convert("RGBA")).copy()
    alpha = arr[:, :, 3]
    visible = alpha > ALPHA_FLOOR
    if not visible.any():
        return img.convert("RGBA")

    # For every transparent pixel, get the nearest visible-pixel coordinates.
    _, indices = distance_transform_edt(~visible, return_indices=True)
    nearest_y, nearest_x = indices
    transparent = ~visible
    for channel in range(3):
        source = arr[:, :, channel]
        filled = source[nearest_y, nearest_x]
        source[transparent] = filled[transparent]
        arr[:, :, channel] = source

    # Keep original alpha exactly; only hidden RGB has changed.
    arr[:, :, 3] = alpha
    return Image.fromarray(arr, "RGBA")


def clean_after_transform(img: Image.Image) -> Image.Image:
    """Remove only virtually invisible edge pixels and clear hidden RGB.

    The threshold is intentionally tiny so the soft watercolor edge remains
    intact. Pixels with meaningful opacity are never changed.
    """
    arr = np.asarray(img.convert("RGBA")).copy()
    alpha = arr[:, :, 3]
    invisible = alpha <= FINAL_ALPHA_THRESHOLD
    arr[invisible, :3] = 0
    arr[invisible, 3] = 0
    return Image.fromarray(arr, "RGBA")


def resize_alpha_safe(img, size, resample=Image.Resampling.LANCZOS):
    """Resize in premultiplied-alpha mode to avoid light or dark halos."""
    rgba = img.convert("RGBA")
    premultiplied = rgba.convert("RGBa")
    resized = premultiplied.resize(size, resample=resample).convert("RGBA")
    return clean_after_transform(resized)


def rotate_alpha_safe(img, angle, resample=Image.Resampling.BICUBIC):
    """Rotate in premultiplied-alpha mode so transparent RGB cannot bleed."""
    rgba = img.convert("RGBA")
    premultiplied = rgba.convert("RGBa")
    rotated = premultiplied.rotate(
        angle, expand=True, resample=resample, fillcolor=(0, 0, 0, 0)
    ).convert("RGBA")
    return clean_after_transform(rotated)


def place_motif_on_canvas(canvas, motif, slot, canvas_size=CANVAS_SIZE):
    target_dim = slot["width"]
    longer_side = max(motif.width, motif.height)
    scale = target_dim / longer_side
    target_w = int(motif.width * scale)
    target_h = int(motif.height * scale)
    resized = resize_alpha_safe(motif, (target_w, target_h), Image.Resampling.LANCZOS)

    # Most calibrated templates mirror the source before applying the fixed
    # template rotation. For special slots such as Snails S01, mirroring must
    # be independent from the angle: rotate first, then mirror the finished
    # placement, so toggling the mirror checkbox cannot visually cancel the
    # intended 34-degree tilt.
    if slot.get("flip_after_rotation", False):
        rotated = rotate_alpha_safe(resized, slot["rotation"], resample=Image.Resampling.BICUBIC)
        if slot.get("flip"):
            rotated = rotated.transpose(Image.Transpose.FLIP_LEFT_RIGHT)
    else:
        if slot.get("flip"):
            resized = resized.transpose(Image.Transpose.FLIP_LEFT_RIGHT)
        rotated = rotate_alpha_safe(resized, slot["rotation"], resample=Image.Resampling.BICUBIC)
    rw, rh = rotated.size
    cx, cy = slot["x"], slot["y"]
    paste_x = cx - rw // 2
    paste_y = cy - rh // 2
    overlay = Image.new("RGBA", canvas.size, (0, 0, 0, 0))
    overlay.alpha_composite(rotated, (paste_x, paste_y))
    canvas = Image.alpha_composite(canvas.convert("RGBA"), overlay)
    offsets = []
    if paste_x < 0: offsets.append((canvas_size, 0))
    if paste_x + rw > canvas_size: offsets.append((-canvas_size, 0))
    if paste_y < 0: offsets.append((0, canvas_size))
    if paste_y + rh > canvas_size: offsets.append((0, -canvas_size))
    if paste_x < 0 and paste_y < 0: offsets.append((canvas_size, canvas_size))
    if paste_x + rw > canvas_size and paste_y < 0: offsets.append((-canvas_size, canvas_size))
    if paste_x < 0 and paste_y + rh > canvas_size: offsets.append((canvas_size, -canvas_size))
    if paste_x + rw > canvas_size and paste_y + rh > canvas_size: offsets.append((-canvas_size, -canvas_size))
    for dx, dy in offsets:
        overlay = Image.new("RGBA", canvas.size, (0, 0, 0, 0))
        overlay.alpha_composite(rotated, (paste_x + dx, paste_y + dy))
        canvas = Image.alpha_composite(canvas.convert("RGBA"), overlay)
    return canvas


def render_template_schematic(template, sample_motif, size=260, canvas_size=CANVAS_SIZE):
    """Real preview: places a sample motif on all slots so you can
    actually see the template layout, not just empty circles."""
    canvas = Image.new("RGBA", (canvas_size, canvas_size), (0, 0, 0, 0))
    for slot in template["main"] + template["secondary"]:
        canvas = place_motif_on_canvas(canvas, sample_motif, slot, canvas_size)
    bg = Image.new("RGBA", canvas.size, (250, 250, 250, 255))
    bg.paste(canvas, (0, 0), canvas)
    return bg.resize((size, size), Image.Resampling.LANCZOS)


def make_sample_motif(size=300):
    """Generates a simple, generic placeholder motif (leaf shape) for the preview."""
    img = Image.new("RGBA", (size, size), (0, 0, 0, 0))
    draw = ImageDraw.Draw(img)
    draw.ellipse([size*0.2, size*0.1, size*0.8, size*0.9], fill=(162, 181, 162, 255))
    draw.ellipse([size*0.35, size*0.3, size*0.65, size*0.6], fill=(250, 250, 250, 255))
    return img


# ---------------------------------------------------------
# UI
# ---------------------------------------------------------
st.title("🌿 Minimal Pattern Studio")
st.caption("Choose a template, upload your motifs, get a finished seamless pattern in seconds")

# --- Step 1: Choose template ---
st.subheader("1. Choose a template")
template_names = list(TEMPLATES.keys())
PREVIEW_COLUMNS = 5
if "selected_template" not in st.session_state:
    st.session_state.selected_template = template_names[0]

for i, name in enumerate(template_names):
    if i % PREVIEW_COLUMNS == 0:
        cols = st.columns(PREVIEW_COLUMNS)
    with cols[i % PREVIEW_COLUMNS]:
        tpl = TEMPLATES[name]
        n_main = len(tpl["main"])
        n_sec = len(tpl["secondary"])
        b64 = TEMPLATE_PREVIEWS_B64.get(name)
        if b64:
            preview_img = Image.open(io.BytesIO(base64.b64decode(b64)))
            st.image(preview_img, use_container_width=True, output_format="PNG")
        else:
            sample = make_sample_motif()
            st.image(render_template_schematic(tpl, sample), use_container_width=True, output_format="PNG")
        label = tpl.get("display_label") or (f"{n_main} motifs" + (f" + {n_sec} small" if n_sec else ""))
        st.markdown(f"**{name}**  \n{label}")
        if st.button("Select", key=f"select_{name}"):
            st.session_state.selected_template = name

selected = st.session_state.selected_template
st.success(f"Selected template: **{selected}**")
template = TEMPLATES[selected]
n_main = len(template["main"])
n_sec = len(template["secondary"])
n_total = template.get("motif_count", n_main + n_sec)

canvas_choice = st.radio(
    "Canvas size",
    options=["2000×2000 px (motifs ~3cm)", "3000×3000 px (motifs ~5cm)"],
    horizontal=True,
)
scale_factor = 1.0 if "2000" in canvas_choice else 1.5
canvas_size = int(CANVAS_SIZE * scale_factor)

st.divider()

# --- Step 2: Upload motifs ---
st.subheader("2. Upload motifs")
st.info("⚠️ Each uploaded file is treated as **one whole motif** — please upload each "
        "motif as its own separate PNG file (don't combine several motifs on one sheet).")

def load_motifs_batch(files):
    motifs = []
    if not files:
        return motifs
    for f in files:
        img = Image.open(f).convert("RGBA")
        img = normalize_to_srgb(img)
        # Preserve the original cleaned PNG edge exactly. Do not unmatte or recolor it.
        # Premultiplied-alpha resizing/rotation below prevents new halos.
        # Normalize every uploaded motif to its actual visible artwork bounds.
        # This removes different amounts of transparent padding from source PNGs,
        # so motifs assigned to equal-size slots render at equal visible sizes.
        img = crop_to_content(img, padding=4)
        motifs.append(img)
    return motifs


def make_motif_size_preview(motif: Image.Image, scale_percent: int, box_size: int = 280) -> Image.Image:
    """Show motifs on equal-size cards using the same longest-side logic as the pattern engine.

    This lets the user compare the *visual* size of different uploaded motifs before
    they are placed into the selected template.
    """
    motif = crop_to_content(motif, padding=4)
    preview = Image.new("RGBA", (box_size, box_size), (250, 250, 250, 255))
    target_long_side = int(box_size * 0.68 * (scale_percent / 100.0))
    longer_side = max(motif.width, motif.height)
    if longer_side <= 0:
        return preview
    ratio = target_long_side / longer_side
    w = max(1, int(round(motif.width * ratio)))
    h = max(1, int(round(motif.height * ratio)))
    resized = resize_alpha_safe(motif, (w, h), Image.Resampling.LANCZOS)
    x = (box_size - w) // 2
    y = (box_size - h) // 2
    preview.alpha_composite(resized, (x, y))
    return preview

main_motifs = []
secondary_motifs = []

if n_sec > 0:
    st.markdown(f"This template has **{n_main} large main slots** and **{n_sec} small secondary slots**. "
                "Upload the two categories separately. You may upload all different motifs, "
                "or upload just **1 main motif** and/or just **1 secondary motif** — "
                "it will repeat automatically within its own group.")
    col_main, col_sec = st.columns(2)
    with col_main:
        st.markdown(f"**Main motifs** (up to {n_main}, or just 1 to repeat)")
        main_files = st.file_uploader("Upload main motifs", type=["png"],
                                       accept_multiple_files=True, key="main_upload",
                                       label_visibility="collapsed")
        main_motifs = load_motifs_batch(main_files)
    with col_sec:
        st.markdown(f"**Secondary motifs** (up to {n_sec}, or just 1 to repeat)")
        sec_files = st.file_uploader("Upload secondary motifs", type=["png"],
                                      accept_multiple_files=True, key="sec_upload",
                                      label_visibility="collapsed")
        secondary_motifs = load_motifs_batch(sec_files)
    all_motifs = main_motifs + secondary_motifs
else:
    st.markdown(f"This template needs **{n_total} motif(s)**. "
                "You can also upload just 1 motif — it will then be repeated on all slots.")
    uploaded_files = st.file_uploader(
        "Upload motif(s) — one separate PNG file per motif",
        type=["png"], accept_multiple_files=True,
    )
    all_motifs = load_motifs_batch(uploaded_files)
    main_motifs = all_motifs

if all_motifs:
    st.success(f"{len(all_motifs)} motif(s) detected.")
    st.markdown("**Adjust motif sizes**")
    st.caption(
        "Compare the motifs side by side and adjust only when one looks visually larger or smaller. "
        "The same uploaded motif keeps this exact size everywhere it repeats in the template."
    )

    motif_scale_percent = {"main": {}, "secondary": {}}

    # Main motifs
    if main_motifs:
        main_cols = st.columns(min(4, max(1, len(main_motifs))))
        for i, motif in enumerate(main_motifs):
            key = f"motif_scale_{selected}_main_{i}"
            if key not in st.session_state:
                st.session_state[key] = 100
            with main_cols[i % len(main_cols)]:
                label = f"Motif {i+1}" if not n_sec else f"Main {i+1}"
                scale_value = st.slider(
                    f"{label} size",
                    min_value=70,
                    max_value=130,
                    value=int(st.session_state[key]),
                    step=1,
                    key=key,
                    format="%d%%",
                )
                motif_scale_percent["main"][i] = scale_value
                st.image(
                    make_motif_size_preview(motif, scale_value),
                    caption=label,
                    width=240,
                    output_format="PNG",
                )

    # Secondary motifs, when the selected template has a second size group
    if secondary_motifs:
        st.markdown("**Secondary motifs**")
        sec_cols = st.columns(min(4, max(1, len(secondary_motifs))))
        for i, motif in enumerate(secondary_motifs):
            key = f"motif_scale_{selected}_secondary_{i}"
            if key not in st.session_state:
                st.session_state[key] = 100
            with sec_cols[i % len(sec_cols)]:
                label = f"Secondary {i+1}"
                scale_value = st.slider(
                    f"{label} size",
                    min_value=70,
                    max_value=130,
                    value=int(st.session_state[key]),
                    step=1,
                    key=key,
                    format="%d%%",
                )
                motif_scale_percent["secondary"][i] = scale_value
                st.image(
                    make_motif_size_preview(motif, scale_value),
                    caption=label,
                    width=240,
                    output_format="PNG",
                )

    st.divider()
    st.subheader("3. Assignment & Preview")

    slot_list = template["main"] + template["secondary"]
    main_pool = main_motifs if main_motifs else all_motifs
    sec_pool = secondary_motifs if secondary_motifs else main_pool

    # ("main"/"secondary", index) per slot
    assignment = {}
    for i, slot in enumerate(template["main"]):
        default_idx = slot.get("motif_index", i) % len(main_pool)
        assignment[slot["id"]] = ("main", default_idx)
    for i, slot in enumerate(template["secondary"]):
        default_idx = slot.get("motif_index", i) % len(sec_pool)
        assignment[slot["id"]] = ("secondary", default_idx)

    def resolve_motif(assign_tuple):
        pool_name, idx = assign_tuple
        pool = main_pool if pool_name == "main" else sec_pool
        return pool[idx % len(pool)]

    left_col, right_col = st.columns([1, 1])

    # Final horizontal flip state for every individual slot.
    # It starts with the template-defined value, but the user may change
    # each repeated placement independently without affecting the others.
    slot_flips = {}

    with left_col:
        st.markdown("**Swap assignment & mirror individual slots**")
        st.caption(
            "Each slot can use a different motif and can be mirrored horizontally on its own. "
            "Template mirror settings are preselected automatically."
        )
        for slot in slot_list:
            is_secondary = slot in template["secondary"]
            pool = sec_pool if is_secondary else main_pool
            pool_name = "secondary" if is_secondary else "main"
            options = list(range(len(pool)))
            current_idx = assignment[slot["id"]][1]

            assignment_col, flip_col = st.columns([3, 2])
            with assignment_col:
                chosen = st.selectbox(
                    f"Slot {slot['id']}", options,
                    index=min(current_idx, len(options) - 1),
                    format_func=lambda x, pn=pool_name: f"{'Secondary' if pn=='secondary' else 'Main'} {x+1}",
                    key=f"assign_{selected}_{slot['id']}",
                )
            with flip_col:
                # Versioned key prevents an older saved checkbox value from
                # overriding the current template default (important for Snails S01).
                flip_key = f"slot_flip_v3_{selected}_{slot['id']}"
                if flip_key not in st.session_state:
                    st.session_state[flip_key] = bool(slot.get("flip", False))
                slot_flips[slot["id"]] = st.checkbox(
                    "↔ Mirror horizontally",
                    key=flip_key,
                )

            assignment[slot["id"]] = (pool_name, chosen)

    canvas = Image.new("RGBA", (canvas_size, canvas_size), (0, 0, 0, 0))
    for slot in slot_list:
        scaled_slot = {
            "x": int(slot["x"] * scale_factor),
            "y": int(slot["y"] * scale_factor),
            "width": int(slot["width"] * scale_factor),
            "rotation": slot["rotation"],
            "flip": slot_flips.get(slot["id"], slot.get("flip", False)),
            "flip_after_rotation": slot.get("flip_after_rotation", False),
        }
        pool_name, motif_idx = assignment[slot["id"]]
        motif = crop_to_content(resolve_motif(assignment[slot["id"]]))

        # Apply the user's visual-size correction to every repetition of this motif.
        # Template-defined size groups (main/secondary) remain intact; this is only
        # a small per-upload correction for motifs that look optically larger/smaller.
        motif_scale = motif_scale_percent.get(pool_name, {}).get(motif_idx, 100) / 100.0
        scaled_slot["width"] = max(1, int(round(scaled_slot["width"] * motif_scale)))

        canvas = place_motif_on_canvas(canvas, motif, scaled_slot, canvas_size)

    with right_col:
        st.markdown("**Preview**")

        bg_mode = st.radio(
            "Background", ["Transparent", "Color"], horizontal=True, key="bg_mode_radio"
        )
        if bg_mode == "Color":
            if "bg_color_value" not in st.session_state:
                st.session_state.bg_color_value = "#F5F5F5"

            def _sync_from_picker():
                st.session_state.bg_color_value = st.session_state.bg_color_picker_widget

            def _sync_from_text():
                st.session_state.bg_color_value = st.session_state.bg_hex_widget

            pick_col, hex_col = st.columns([1, 2])
            with pick_col:
                st.color_picker(
                    "Pick a color", value=st.session_state.bg_color_value,
                    key="bg_color_picker_widget", on_change=_sync_from_picker,
                )
            with hex_col:
                st.text_input(
                    "Or type a hex code", value=st.session_state.bg_color_value,
                    key="bg_hex_widget", on_change=_sync_from_text,
                )

            bg_hex = st.session_state.bg_color_value
            try:
                bg_hex_clean = bg_hex.strip().lstrip("#")
                if len(bg_hex_clean) != 6:
                    raise ValueError
                bg_rgb = tuple(int(bg_hex_clean[i:i+2], 16) for i in (0, 2, 4))
            except Exception:
                st.warning("Enter a valid hex code, e.g. #F5F5F5 — using default gray for now.")
                bg_rgb = (245, 245, 245)
            export_canvas = Image.new("RGBA", canvas.size, (*bg_rgb, 255))
            export_canvas.paste(canvas, (0, 0), canvas)
        else:
            bg_rgb = (250, 250, 250)
            export_canvas = canvas

        preview_bg = Image.new("RGBA", canvas.size, (*bg_rgb, 255))
        preview_bg.paste(canvas, (0, 0), canvas)
        # Server-side sharp downscale for on-screen display — large enough to look genuinely sharp
        display_size = min(1600, preview_bg.width)
        display_preview = preview_bg.resize(
            (display_size, display_size), Image.Resampling.LANCZOS
        )
        st.image(display_preview, use_container_width=True, output_format="PNG")

        buf = io.BytesIO()
        export_canvas.save(buf, format="PNG", dpi=(DPI, DPI))
        button_label = ("📥 Download pattern as PNG (with background color)" if bg_mode == "Color"
                         else "📥 Download pattern as transparent PNG")
        st.download_button(
            button_label,
            data=buf.getvalue(),
            file_name=f"minimal_pattern_studio_{selected.lower().replace(' ', '_')}.png",
            mime="image/png",
        )
else:
    st.info("No motifs uploaded yet.")

